            match = re.search(r'(Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)\s*(?:(\d{1,2})(?:st|nd|rd|th)?,)?\s*(\d{4})', date_str, re.IGNORECASE)
            if match:
